// Build email digest HTML
const restaurant = $('Loop Restaurants').item.json.fields;
const responses = $input.all();

const restaurantName = restaurant.restaurant_name;
const ownerName = restaurant.owner_name;
const ownerEmail = restaurant.owner_email;
const responseCount = responses.length;

// Group responses by rating
const by_rating = { 5: [], 4: [], 3: [], 2: [], 1: [] };
for (const resp of responses) {
  const review = resp.json.fields.review; // Linked review
  const rating = parseInt(review?.star_rating?.replace(' Stars', '') || '3');
  by_rating[rating].push(resp);
}

// Generate approval links (unique tokens)
const crypto = require('crypto');
const approval_links = responses.map(r => ({
  response_id: r.json.id,
  token: crypto.randomBytes(16).toString('hex'),
  expires: new Date(Date.now() + 72 * 60 * 60 * 1000).toISOString() // 72 hours
}));

// Build HTML email body
let emailHtml = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; max-width: 700px; margin: 0 auto; }
    .header { background: #4285f4; color: white; padding: 20px; text-align: center; }
    .summary { background: #f8f9fa; padding: 15px; margin: 20px 0; border-radius: 8px; }
    .review-block { border: 1px solid #ddd; margin: 15px 0; padding: 15px; border-radius: 8px; }
    .stars { color: #ffa500; font-size: 18px; }
    .response-box { background: #e8f4fd; padding: 12px; margin: 10px 0; border-left: 4px solid #4285f4; }
    .button { display: inline-block; padding: 10px 20px; margin: 5px; text-decoration: none; border-radius: 4px; font-weight: bold; }
    .approve { background: #0d7377; color: white; }
    .edit { background: #ffa500; color: white; }
    .reject { background: #d32f2f; color: white; }
    .footer { text-align: center; color: #666; font-size: 12px; margin-top: 30px; padding: 20px; border-top: 1px solid #ddd; }
  </style>
</head>
<body>
  <div class="header">
    <h1>📊 ${restaurantName}</h1>
    <h2>${responseCount} Review Response${responseCount !== 1 ? 's' : ''} Ready for Approval</h2>
  </div>

  <p>Hi ${ownerName},</p>
  <p>Your weekly review summary is here! We've generated responses for ${responseCount} new review${responseCount !== 1 ? 's' : ''} this week.</p>

  <div class="summary">
    <h3>📊 THIS WEEK'S SUMMARY</h3>
    <p><strong>Reviews:</strong> ${responseCount} new</p>
    ${Object.entries(by_rating).reverse().map(([rating, items]) => 
      items.length > 0 ? `<p>⭐`.repeat(rating) + ` ${rating} star${rating !== '1' ? 's' : ''}: ${items.length} review${items.length !== 1 ? 's' : ''}</p>` : ''
    ).join('')}
    <p><strong>Deadline:</strong> ${new Date(Date.now() + 72 * 60 * 60 * 1000).toLocaleDateString()} (72 hours)</p>
  </div>

  <hr/>
`;

// Add each review and response
let reviewNum = 1;
for (const resp of responses) {
  const review_data = resp.json.fields.review || {};
  const rating = parseInt(review_data.star_rating?.replace(' Stars', '') || '3');
  const stars = '⭐'.repeat(rating);
  const reviewer = review_data.reviewer_name || 'Anonymous';
  const review_text = review_data.review_text || 'No comment';
  const response_text = resp.json.fields.generated_text;
  const response_id = resp.json.id;

  // Get approval token for this response
  const token = approval_links.find(l => l.response_id === response_id)?.token;

  emailHtml += `
  <div class="review-block">
    <h3>Review #${reviewNum} - <span class="stars">${stars}</span> by ${reviewer}</h3>
    <p><em>"${review_text.substring(0, 200)}${review_text.length > 200 ? '...' : ''}"</em></p>

    <div class="response-box">
      <strong>📝 AI Response:</strong><br/>
      ${response_text}
    </div>

    <div style="text-align: center; margin-top: 15px;">
      <a href="http://YOUR_N8N_INSTANCE/webhook/approve-response?token=${token}&action=approve" class="button approve">✅ Approve</a>
      <a href="http://YOUR_N8N_INSTANCE/webhook/approve-response?token=${token}&action=edit" class="button edit">✏️ Edit</a>
      <a href="http://YOUR_N8N_INSTANCE/webhook/approve-response?token=${token}&action=reject" class="button reject">❌ Reject</a>
    </div>
  </div>
  <hr/>
  `;

  reviewNum++;
}

emailHtml += `
  <div style="text-align: center; margin: 30px 0;">
    <a href="http://YOUR_N8N_INSTANCE/webhook/approve-all?restaurant=${restaurant.id}" class="button approve" style="font-size: 18px; padding: 15px 30px;">✅ Approve All ${responseCount} Responses</a>
  </div>

  <div class="footer">
    <p>⏰ You have 72 hours to approve these responses. After that, they'll be cancelled.</p>
    <p>Questions? <a href="mailto:support@yourapp.com">Contact Support</a> | <a href="http://YOUR_DASHBOARD_URL">View Dashboard</a></p>
  </div>
</body>
</html>
`;

return [{
  json: {
    to: ownerEmail,
    subject: `${restaurantName} - ${responseCount} Review Response${responseCount !== 1 ? 's' : ''} Ready for Approval`,
    html: emailHtml,
    approval_links: approval_links,
    restaurant_id: restaurant.id,
    restaurant_name: restaurantName
  }
}];
